/**
 * frontend/src/App.jsx
 *
 * Screens: UseCaseLibrary → IntakeFlow → SessionView (WebSocket).
 */

import React, { useCallback, useState } from "react";
import UseCaseLibrary from "./components/UseCaseLibrary";
import IntakeFlow from "./components/IntakeFlow";
import SessionView from "./components/SessionView";

const SCREENS = {
  LIBRARY: "library",
  INTAKE: "intake",
  SESSION: "session",
};

function App() {
  const [screen, setScreen] = useState(SCREENS.LIBRARY);
  const [intakeMountKey, setIntakeMountKey] = useState(0);
  const [selectedUseCase, setSelectedUseCase] = useState(null);
  const [sessionConfig, setSessionConfig] = useState(null);

  const handleUseCaseSelect = useCallback(({ card, familyKey }) => {
    setSelectedUseCase({ ...card, familyKey });
    setIntakeMountKey((k) => k + 1);
    setScreen(SCREENS.INTAKE);
  }, []);

  const handleIntakeComplete = useCallback((config) => {
    setSessionConfig(config);
    setScreen(SCREENS.SESSION);
  }, []);

  const handleBackToLibrary = useCallback(() => {
    setScreen(SCREENS.LIBRARY);
    setSelectedUseCase(null);
    setSessionConfig(null);
  }, []);

  return (
    <>
      {screen === SCREENS.LIBRARY && <UseCaseLibrary onSelect={handleUseCaseSelect} />}
      {screen === SCREENS.INTAKE && (
        <IntakeFlow
          key={intakeMountKey}
          selectedUseCase={selectedUseCase}
          onComplete={handleIntakeComplete}
          onBack={handleBackToLibrary}
        />
      )}
      {screen === SCREENS.SESSION && sessionConfig && (
        <SessionView sessionConfig={sessionConfig} onSynthesisComplete={() => {}} />
      )}
    </>
  );
}

export default App;
